'use strict';

var path = require('node:path');
var frontendCountry_config = require('frontend-country_config');
var fs = require('./fs.js');

function createCountriesLocales() {
    return new Map(Object.values(frontendCountry_config.getCountriesData()).map(({ id, locale }) => [
        id,
        locale.replace('_', '-'),
    ]));
}
function createTranslations(srcPath) {
    const translations = new Map();
    const translationDirs = fs.readLibTranslationDirs();
    // Add app translations dir
    translationDirs.push(path.join(srcPath, 'translations'));
    translationDirs
        .flatMap((dir) => fs.readTranslationsDirs(dir))
        .forEach((dirPath) => {
        if (!dirPath) {
            return;
        }
        const locale = path.basename(dirPath);
        translations.set(locale, Object.assign(translations.get(locale) ?? {}, fs.readMessagesFile(dirPath) ?? {}));
    });
    translations.forEach((value, key) => {
        translations.set(key, Object.freeze(value));
    });
    return translations;
}

exports.createCountriesLocales = createCountriesLocales;
exports.createTranslations = createTranslations;
